target_district = "Saadiyat Island"

saadiyat_investors = investors[investors["preferred_district"].eq(target_district)].copy()

def _suffix_multiplier(part):
    s = str(part).strip().upper().replace(",", "").replace("AED", "").replace(" ", "")
    if s.endswith("B"):
        return 1000000000.0
    if s.endswith("M"):
        return 1000000.0
    if s.endswith("K"):
        return 1000.0
    return None

def _to_aed(part, default_multiplier=None):
    s = str(part).strip().upper().replace(",", "").replace("AED", "").replace(" ", "")
    multiplier = default_multiplier if default_multiplier is not None else 1.0
    if s.endswith("B"):
        multiplier = 1000000000.0
        s = s[:-1]
    elif s.endswith("M"):
        multiplier = 1000000.0
        s = s[:-1]
    elif s.endswith("K"):
        multiplier = 1000.0
        s = s[:-1]
    return float(s) * multiplier

def _capital_midpoint_aed(capital_range):
    s = str(capital_range).strip().upper().replace("–", "-").replace("—", "-").replace(" TO ", "-")
    parts = [p for p in s.split("-") if p.strip() != ""]
    if len(parts) == 1:
        return _to_aed(parts[0])
    right_multiplier = _suffix_multiplier(parts[-1])
    low = _to_aed(parts[0], right_multiplier)
    high = _to_aed(parts[-1])
    return (low + high) / 2.0

