def _amount_to_aed(token):
    s = str(token).strip().upper().replace(',', '').replace('AED', '').strip()
    if s.endswith('+'):
        s = s[:-1].strip()
    if s.endswith('B'):
        return float(s[:-1]) * 1000000000
    if s.endswith('M'):
        return float(s[:-1]) * 1000000
    return float(s)


def _capital_midpoint_aed(band):
    s = str(band).strip().upper().replace(' ', '').replace(',', '').replace('AED', '')
    s = s.replace('–', '-').replace('—', '-')
    if '-' in s:
        lo, hi = s.split('-', 1)
        return (_amount_to_aed(lo) + _amount_to_aed(hi)) / 2
    return _amount_to_aed(s)

